int* topSort(int* returnSize, int* deg, int** graph, int* graphColSize, int* items, int itemsSize) {
    *returnSize = 0;
    int Q[itemsSize];
    int left = 0, right = 0;
    for (int i = 0; i < itemsSize; i++) {
        if (deg[items[i]] == 0) {
            Q[right++] = items[i];
        }
    }
    int* res = malloc(sizeof(int) * itemsSize);
    while (left < right) {
        int u = Q[left++];
        res[(*returnSize)++] = u;
        for (int i = 0; i < graphColSize[u]; i++) {
            int v = graph[u][i];
            if (--deg[v] == 0) {
                Q[right++] = v;
            }
        }
    }
    if (*returnSize == itemsSize) {
        return res;
    }
    *returnSize = 0;
    return NULL;
}

