        struct unordered_map* tmp = NULL;
        HASH_FIND_INT(occur, &arr[i], tmp);
        if (tmp == NULL) {
            tmp = malloc(sizeof(struct unordered_map));
            tmp->key = arr[i], tmp->val = 1;
            HASH_ADD_INT(occur, key, tmp);
        } else {
            (tmp->val)++;
