                    dp[i][j][0] += board[i][j] - '0';
                }
            }
        }
    }
    int* res = (int*)malloc(2 * sizeof(int));
    *returnSize = 2;
    if (dp[0][0][0] != -1) {
        res[0] = dp[0][0][0];
        res[1] = dp[0][0][1] % MOD;
    } else {
        res[0] = 0;
        res[1] = 0;
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            free(dp[i][j]);
        }
        free(dp[i]);
    }
    free(dp);
    return res;
}

