        for i in range(n):
            if indeg[i] == 0:
                root = i
                break
        if root == -1:
            return False


        seen = set([root])
        q = collections.deque([root])

        while len(q) > 0:
            u = q.popleft()
            if leftChild[u] != -1:
                if leftChild[u] in seen:
                    return False
                seen.add(leftChild[u])
                q.append(leftChild[u])
            if rightChild[u] != -1:
                if rightChild[u] in seen:
                    return False
                seen.add(rightChild[u])
                q.append(rightChild[u])

        return len(seen) == n

class Solution:
    def divide(self, n):
        ans = [0, int(1e9)]
        for i in range(1, n + 1):
            if n % i == 0:
                if abs(n // i - i) < abs(ans[0] - ans[1]):
                    ans = [n // i, i]
        return ans

    def closestDivisors(self, num: int) -> List[int]:
        ans = [0, int(1e9)]
        for i in range(num + 1, num + 3):
            cur = self.divide(i)
            if abs(cur[0] - cur[1]) < abs(ans[0] - ans[1]):
                ans = cur
        return ans

