int maxDotProduct(int* nums1, int nums1Size, int* nums2, int nums2Size) {
    int m = nums1Size;
    int n = nums2Size;
    int** f = (int**)malloc(m * sizeof(int*));
    for (int i = 0; i < m; i++) {
        f[i] = (int*)malloc(n * sizeof(int));
    }

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            int xij = nums1[i] * nums2[j];
            f[i][j] = xij;
            if (i > 0) {
                f[i][j] = fmax(f[i][j], f[i - 1][j]);
            }
            if (j > 0) {
                f[i][j] = fmax(f[i][j], f[i][j - 1]);
            }
            if (i > 0 && j > 0) {
                f[i][j] = fmax(f[i][j], f[i - 1][j - 1] + xij);
            }
        }
    }

    int result = f[m-1][n-1];

    // 释放内存
    for (int i = 0; i < m; i++) {
        free(f[i]);
    }
    free(f);

    return result;
}

