    if (vi[cur]) {
        return;
    }
    vi[cur] = true;
    for (int j = 0; j < gColSize[cur]; j++) {
        int ne = g[cur][j];
        dfs(g, gColSize, isPre, vi, ne, numCourses);
        isPre[cur][ne] = true;
        for (int i = 0; i < numCourses; ++i) {
            isPre[cur][i] = isPre[cur][i] | isPre[ne][i];
        }
    }
}

