public class Solution {
    public int MinimumOneBitOperations(int n) {
        if (n == 0) {
            return 0;
        }
        int x = 31 - System.Numerics.BitOperations.LeadingZeroCount((uint)n);
        // 第 x 位为 1
        int ans = 1 << x;
        // 二进制码的当前位
        int bit = 1;
        for (int i = x - 1; i >= 0; --i) {
            // 如果格雷码的第 i 位为 1，那么二进制码的当前位与上一个高位不相同
            if ((n & (1 << i)) != 0) {
                bit ^= 1;
            }
            // 如果当前位为 1，将其加入答案
            if (bit != 0) {
                ans |= (1 << i);
            }
        }
        return ans;
    }
}

