    int firstArr[n], secondArr[n];
    int firstArrSize = 0, secondArrSize = 0;
    for (int i = 0; i < n; ++i) {
        if (degree[i] > first) {
            second = first;
            secondArrSize = firstArrSize;
            memcpy(secondArr, firstArr, sizeof(int) * firstArrSize);
            first = degree[i];
            firstArrSize = 0;
            firstArr[firstArrSize++] = i;
