            secondArrSize = 0;
            second = degree[i];
            secondArr[secondArrSize++] = i;
        } else if (degree[i] == second) {
            secondArr[secondArrSize++] = i;
        }
    }
    if (firstArrSize == 1) {
        int u = firstArr[0];
        for (int i = 0; i < secondArrSize; i++) {
            int v = secondArr[i];
            if (!connect[u][v]) {
                return first + second;
            }
        }
        return first + second - 1;
    } else {
        if (firstArrSize * (firstArrSize - 1) / 2 > roadsSize) {
            return first * 2;
