    int gSize = 0, preSumSize = 0;
    preSum[preSumSize++] = 0;
    for (int i = 0; i < numsSize; i++) {
        if (nums[i] == 1) {
            g[gSize++] = i - gSize;
            preSum[preSumSize++] = preSum[preSumSize - 1] + g[gSize - 1];
        }
    }
    int m = gSize, res = INT_MAX;
    for (int i = 0; i <= m - k; i++) {
        int mid = i + k / 2;
        res = min(res, (1 - k % 2) * g[mid] +  \
                        (preSum[i + k] - preSum[mid + 1]) - \
                        (preSum[mid] - preSum[i]));
    }
    return res;
}

