const int HIGH_BIT = 14;

Trie * creatTrieNode() {
    Trie *obj = (Trie *)malloc(sizeof(Trie));
    obj->son[0] = obj->son[1] = NULL;
    obj->sum = 0;
    return obj;
}

void freeTrie(Trie *root) {
    if (!root) {
        return;
    }
    freeTrie(root->son[0]);
    freeTrie(root->son[1]);
    free(root);
}

void add(int num, Trie *root) {
    Trie* cur = root;
    for (int k = HIGH_BIT; k >= 0; k--) {
        int bit = (num >> k) & 1;
        if (cur->son[bit] == NULL) {
            cur->son[bit] = creatTrieNode();
        }
        cur = cur->son[bit];
        cur->sum++;
    }
}

int get(int num, int x, const Trie *root) {
    const Trie* cur = root;
    int sum = 0;
    for (int k = HIGH_BIT; k >= 0; k--) {
        int r = (num >> k) & 1;
        if ((x >> k) & 1) {
            if (cur->son[r] != NULL) {
                sum += cur->son[r]->sum;
            }
            if (cur->son[r ^ 1] == NULL) {
                return sum;
            }
            cur = cur->son[r ^ 1];
        } else {
            if (cur->son[r] == NULL) {
                return sum;
            }
            cur = cur->son[r];
        }
    }
    sum += cur->sum;
    return sum;
}

int f(const int *nums, int numsSize, int x) {
    Trie *root = creatTrieNode();
    int res = 0;
    for (int i = 1; i < numsSize; i++) {
        add(nums[i - 1], root);
        res += get(nums[i], x, root);
    }
    freeTrie(root);
    return res;
}

int countPairs(int* nums, int numsSize, int low, int high) {
    return f(nums, numsSize, high) - f(nums, numsSize, low - 1);
}

