type trie struct{ root *trieNode }

func (t *trie) put(v int) *trieNode {
    o := t.root
    for i := trieBitLen; i >= 0; i-- {
        b := v >> i & 1
        if o.son[b] == nil {
            o.son[b] = &trieNode{}
        }
        o = o.son[b]
        o.cnt++
    }
    return o
}

func (t *trie) countLimitXOR(v, limit int) (cnt int) {
    o := t.root
    for i := trieBitLen; i >= 0; i-- {
        b := v >> i & 1
        if limit>>i&1 > 0 {
            if o.son[b] != nil {
                cnt += o.son[b].cnt
            }
            b ^= 1
        }
        if o.son[b] == nil {
            return
        }
        o = o.son[b]
    }
    return
}

