class Solution {
private:
    using LL = long long;
    static constexpr int mod = 1000000007;

public:
    int maxSumMinProduct(vector<int>& nums) {
        int n = nums.size();
        // 数组 left 初始化为 0，数组 right 初始化为 n-1
        // 设置为元素不存在时的特殊值
        vector<int> left(n), right(n, n - 1);
        // 单调栈
        stack<int> s;
        for (int i = 0; i < n; ++i) {
            while (!s.empty() && nums[s.top()] >= nums[i]) {
                // 这里的 right 是非严格定义的，right[i] 是右侧最近的小于等于 nums[i] 的元素下标
                right[s.top()] = i - 1;
                s.pop();
            }
            if (!s.empty()) {
                // 这里的 left 是严格定义的，left[i] 是左侧最近的严格小于 nums[i] 的元素下标
                left[i] = s.top() + 1;
            }
            s.push(i);
        }

        // 前缀和
        vector<LL> pre(n + 1);
        for (int i = 1; i <= n; ++i) {
            pre[i] = pre[i - 1] + nums[i - 1];
        }

        LL best = 0;
        for (int i = 0; i < n; ++i) {
            best = max(best, (pre[right[i] + 1] - pre[left[i]]) * nums[i]);
        }
        return best % mod;
    }
};

struct ListNode *createListNode(int val) {
    struct ListNode *obj = (struct ListNode *)malloc(sizeof(struct ListNode));
    obj->val = val;
    obj->next = NULL;
    return obj;
}

void freeList(struct ListNode *list) {
    while (list) {
        struct ListNode *p = list;
        list = list->next;
        free(p);
    }
}

int largestPathValue(char* colors, int** edges, int edgesSize, int* edgesColSize) {
    int n = strlen(colors);
    // 邻接表
    struct ListNode *g[n];
    // 节点的入度统计，用于找出拓扑排序中最开始的节点
    int indeg[n];
    for (int i = 0; i < n; i++) {
        g[i] = NULL;
        indeg[i] = 0;
    }
    for (int i = 0; i < edgesSize; ++i) {
        int x = edges[i][0], y = edges[i][1];
        ++indeg[y];
        struct ListNode *node = createListNode(y);
        node->next = g[x];
        g[x] = node;
    }

    // 记录拓扑排序过程中遇到的节点个数
    // 如果最终 found 的值不为 n，说明图中存在环
    int found = 0;
    int f[n][26];
    int queue[n];
    int head = 0, tail = 0;
    memset(f, 0, sizeof(f));
    for (int i = 0; i < n; ++i) {
        if (indeg[i] == 0) {
            queue[tail++] = i;
        }
    }

    while (head != tail) {
        ++found;
        int u = queue[head];
        head++;
        // 将节点 u 对应的颜色增加 1
        ++f[u][colors[u] - 'a'];
        // 枚举 u 的后继节点 v
        for (struct ListNode *p = g[u]; p != NULL; p = p->next) {
            int v = p->val;
            --indeg[v];
            // 将 f(v,c) 更新为其与 f(u,c) 的较大值
            for (int c = 0; c < 26; ++c) {
                f[v][c] = (f[v][c] > f[u][c]) ? f[v][c] : f[u][c];
            }
            if (indeg[v] == 0) {
                queue[tail++] = v;
            }
        }
    }

    if (found != n) {
        return -1;
    }
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        for (int c = 0; c < 26; ++c) {
            if (f[i][c] > ans) {
                ans = f[i][c];
            }
        }
        freeList(g[i]);
    }

    return ans;
}

