class Solution {
public:
    string sortSentence(string s) {
        vector<string> arr(9);   // 单词数组
        string tmp = "";   // 当前单词
        int n = 0;   // 单词数量
        // 遍历字符串
        for (auto c: s){
            if (c >= '0' && c <= '9'){
                // 如果为数字，计算对应的单词数组下标，将单词放入对应位置，并清空当前单词
                // 数组下标为 0 开头，位置索引为 1 开头
                arr[c-'0'-1] = tmp;
                tmp.clear();
                ++n;
            }
            else if (c != ' '){
                // 如果为字母，更新当前单词
                tmp.push_back(c);
            }
        }
        string res = arr[0];   // 原本顺序的句子 
        for (int i = 1; i < n; ++i){
            res += " " + arr[i];
        }
        return res;
    }
};

